export interface NetworkSummary {
  status: EdgeStatus;
  label: string;
  operational: number;
  total: number;
  avgUptime: number;
}

/** Derive the overall network health from the individual edge nodes. */
export function getNetworkSummary(nodes: EdgeNode[]): NetworkSummary {
  const total = nodes.length;
  const operational = nodes.filter((n) => n.status === "operational").length;
  const hasDown = nodes.some((n) => n.status === "down");
  const hasDegraded = nodes.some((n) => n.status === "degraded");

  const status: EdgeStatus = hasDown
    ? "down"
    : hasDegraded
      ? "degraded"
      : "operational";

  const label = hasDown
    ? "Partial outage"
    : hasDegraded
      ? "Degraded performance"
      : "All systems operational";

  const avgUptime =
    nodes.reduce((sum, n) => sum + n.uptime, 0) / Math.max(total, 1);

  return { status, label, operational, total, avgUptime };
}

"use client";

import { cn } from "@/lib/utils";
import { MapMarker, MarkerContent, MarkerTooltip } from "@/components/ui/map";
import { statusMeta, type EdgeNode } from "../data";

interface EdgeNodeMarkerProps {
  node: EdgeNode;
}

export function EdgeNodeMarker({ node }: EdgeNodeMarkerProps) {
  const meta = statusMeta[node.status];

  return (
    <MapMarker longitude={node.lng} latitude={node.lat}>
      <MarkerContent>
        <div className="group flex size-4 items-center justify-center">
          <span
            className={cn(
              "inline-flex size-2 rounded-full transition-transform group-hover:scale-125",
              meta.dot,
            )}
          />
        </div>
      </MarkerContent>
      <MarkerTooltip
        offset={10}
        className="bg-popover text-popover-foreground min-w-28 border p-2"
      >
        <div className="flex items-center gap-1.5">
          <span className={cn("size-1.5 rounded-full", meta.dot)} />
          <span className="text-[11px] font-medium">{node.city}</span>
          <span className="text-muted-foreground ml-auto font-mono text-[11px] uppercase">
            {node.id}
          </span>
        </div>
        <div className="text-muted-foreground mt-1.5 flex items-center justify-between gap-3 text-[11px]">
          <span>{node.status === "down" ? "—" : `${node.latency} ms`}</span>
          <span className="tabular-nums">{node.uptime.toFixed(2)}%</span>
        </div>
      </MarkerTooltip>
    </MapMarker>
  );
}

"use client";

import { cn } from "@/lib/utils";
import { getNetworkSummary, statusMeta, type EdgeNode } from "../data";

interface StatusSidebarProps {
  nodes: EdgeNode[];
}

export function StatusSidebar({ nodes }: StatusSidebarProps) {
  const summary = getNetworkSummary(nodes);
  const summaryMeta = statusMeta[summary.status];

  return (
    <div className="bg-card flex w-56 shrink-0 flex-col overflow-hidden border-r">
      <div className="border-b p-3">
        <p className="text-foreground text-sm font-semibold">Edge Network</p>

